"use strict";(self.webpackChunkdiscord_bots=self.webpackChunkdiscord_bots||[]).push([[354],{3597:(e,t,d)=>{d.r(t),d.d(t,{data:()=>a});const a={key:"v-7da32354",path:"/awesome_bot/commands.html",title:"Commands",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"How to Read",slug:"how-to-read",children:[{level:3,title:"Command",slug:"command",children:[]},{level:3,title:"Aliases",slug:"aliases",children:[]},{level:3,title:"Usage",slug:"usage",children:[]},{level:3,title:"Description",slug:"description",children:[]},{level:3,title:"Required Permissions",slug:"required-permissions",children:[]},{level:3,title:"Example & Result",slug:"example-result",children:[]}]},{level:2,title:"List of Commands",slug:"list-of-commands",children:[]}],filePathRelative:"awesome_bot/commands.md",git:{updatedTime:1629055125e3,contributors:[]}}},3312:(e,t,d)=>{d.r(t),d.d(t,{default:()=>o});const a=(0,d(6252).uE)('<h1 id="commands" tabindex="-1"><a class="header-anchor" href="#commands" aria-hidden="true">#</a> Commands</h1><h2 id="how-to-read" tabindex="-1"><a class="header-anchor" href="#how-to-read" aria-hidden="true">#</a> How to Read</h2><h3 id="command" tabindex="-1"><a class="header-anchor" href="#command" aria-hidden="true">#</a> Command</h3><p>This is the command name. This is what you enter to trigger the command.</p><h3 id="aliases" tabindex="-1"><a class="header-anchor" href="#aliases" aria-hidden="true">#</a> Aliases</h3><p>Aliases can also be entered in place of the command name, so that the same result can be obtained from multiple ways.</p><h3 id="usage" tabindex="-1"><a class="header-anchor" href="#usage" aria-hidden="true">#</a> Usage</h3><p>Usage defines how to use each item. Incorporate the prefix before. Items surrounded in angle brackets <code>&lt;&gt;</code> must be filled in which something. Items surrounded by square brackets <code>[]</code> are optional, the command will function without it. Items without any of those are inputted as-is. Items separated by a vertical line <code>|</code> mean either A <em>or</em> B, choose one.</p><h3 id="description" tabindex="-1"><a class="header-anchor" href="#description" aria-hidden="true">#</a> Description</h3><p>This is a description about what the command does.</p><h3 id="required-permissions" tabindex="-1"><a class="header-anchor" href="#required-permissions" aria-hidden="true">#</a> Required Permissions</h3><p>Some commands shouldn&#39;t be able to be executed by all members. These define the permissions the member must have in order to use the command.</p><h3 id="example-result" tabindex="-1"><a class="header-anchor" href="#example-result" aria-hidden="true">#</a> Example &amp; Result</h3><p>This is an example of the command used in action.</p><h2 id="list-of-commands" tabindex="-1"><a class="header-anchor" href="#list-of-commands" aria-hidden="true">#</a> List of Commands</h2><table><thead><tr><th>Command</th><th>Aliases</th><th>Usage</th><th>Description</th><th>Required Permissions</th><th>Example &amp; Result</th></tr></thead><tbody><tr><td><code>eval</code></td><td>N/A</td><td><code>eval &lt;JavaScript Code&gt;</code></td><td>Execute a line of JavaScript code, can be useful for single-use configuration</td><td>Administrator</td><td>WIP</td></tr><tr><td><code>help</code></td><td><code>commands</code></td><td><code>help [Command Name]</code></td><td>Gets a list of all commands to use, or a description of a command if an argument is provided</td><td>N/A</td><td>WIP</td></tr><tr><td><code>leaderboard</code></td><td>N/A</td><td><code>leaderboard</code></td><td>Gets the leaderboard for the leveling system. Only displays the first 20 members.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>ping</code></td><td>N/A</td><td><code>ping</code></td><td>Checks to see the response time for Awesome Bot, and if it&#39;s still alive.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>presence</code></td><td>N/A</td><td><code>presence dnd|idle|invisible|online</code></td><td>Sets the bot to appear online, idle, do not disturb, or invisible.</td><td>Administrator</td><td>WIP</td></tr><tr><td><code>rank</code></td><td>N/A</td><td><code>rank [User]</code></td><td>Gets the rank of the member, or the pinged member if an argument is provided.</td><td>N/A</td><td>WIP</td></tr><tr><td><code>repo</code></td><td>N/A</td><td><code>repo</code></td><td>Gets the link to the repository for Awesome Bot</td><td>N/A</td><td>WIP</td></tr><tr><td><code>status</code></td><td>N/A</td><td><code>status competing|custom_status|listening|playing|streaming|watching &lt;Name&gt;</code></td><td>Sets if Awesome Bot is competing, a custom status, listening, playing, streaming, or watching a certain thing.</td><td>Administrator</td><td>WIP</td></tr></tbody></table>',16),o={render:function(e,t){return a}}}}]);